oxy_webhelp_navlinks = {"k8s_vm_recovery_live_mount-d30753e22329":{"topics":[{"title":"Prerequisites for OpenShift virtual machine Live Mount","shortdesc":"<p class=\"shortdesc\">Before creating a Live Mount, you must ensure the Kubernetes cluster environment is         configured to support network file system, specific version requirements, and the required         volume types.<\/p>","href":"kubernetes\/k8s_prereqs_openshift_vm_live_mount.html","attributes":{"data-id":"k8s_prereqs_openshift_vm_live_mount"},"menu":{"hasChildren":false},"tocID":"k8s_prereqs_openshift_vm_live_mount-d30753e22342","topics":[]},{"title":"Creating a Live Mount for OpenShift virtual machines","shortdesc":"<p class=\"shortdesc\">Create a Live Mount for an OpenShift virtual machine on a Kubernetes cluster from a         snapshot on the Rubrik cluster. The live mounted virtual machine uses the Rubrik cluster as         its underlying storage.<\/p>","href":"kubernetes\/k8s_creating_live_mount.html","attributes":{"data-id":"k8s_creating_live_mount"},"menu":{"hasChildren":false},"tocID":"k8s_creating_live_mount-d30753e22353","topics":[]},{"title":"Unmounting an OpenShift virtual machine","shortdesc":"<p class=\"shortdesc\">Unmount a recovered OpenShift virtual machine from <span class=\"ph\">RSC<\/span>.<\/p>","href":"kubernetes\/k8s_unmounting_vm.html","attributes":{"data-id":"k8s_unmounting_vm"},"menu":{"hasChildren":false},"tocID":"k8s_unmounting_vm-d30753e22364","topics":[]},{"title":"Unmount behavior for OpenShift virtual machines","shortdesc":"<p class=\"shortdesc\">Unmount a Live Mount to end the recovery session and clean up Rubrik-hosted         resources. The final state of the virtual machine depends on its storage status and whether         a storage migration occurred during the session.<\/p>","href":"kubernetes\/k8s_unmount_behavior_openshift_vms.html","attributes":{"data-id":"k8s_unmount_behavior_openshift_vms"},"menu":{"hasChildren":false},"tocID":"k8s_unmount_behavior_openshift_vms-d30753e22378","topics":[]},{"title":"NFS client IP configuration","shortdesc":"<p class=\"shortdesc\">Rubrik uses specific IP addresses from Kubernetes nodes to expose NFS shares during a Live Mount operation.<\/p>","href":"kubernetes\/k8s_nfs_ip_configuration.html","attributes":{"data-id":"k8s_nfs_ip_configuration"},"menu":{"hasChildren":false},"tocID":"k8s_nfs_ip_configuration-d30753e22389","topics":[]},{"title":"Mounting OpenShift virtual machine disks","shortdesc":"<p class=\"shortdesc\">Mount specific virtual disks from an OpenShift virtual machine snapshot to an         existing virtual machine. The mounted virtual disks use the Rubrik cluster as their         datastore.<\/p>","href":"kubernetes\/k8s_mounting_virtual_disks.html","attributes":{"data-id":"k8s_mounting_virtual_disks"},"menu":{"hasChildren":false},"tocID":"k8s_mounting_virtual_disks-d30753e22400","topics":[]},{"title":"Unmounting virtual disks from an OpenShift virtual machine","shortdesc":"<p class=\"shortdesc\">Unmount virtual disks that were mounted to an OpenShift virtual machine from <span class=\"ph\">RSC<\/span>.<\/p>","href":"kubernetes\/k8s_unmounting_virtual_disks.html","attributes":{"data-id":"k8s_unmounting_virtual_disks"},"menu":{"hasChildren":false},"tocID":"k8s_unmounting_virtual_disks-d30753e22411","topics":[]}]}};